// Get LED pattern for specified time (with rounding to nearest valid minute)
static inline const led_pattern_t* get_led_pattern(uint8_t hour, uint8_t minute) {
    // Normalize inputs
    hour = hour % 24;
    
    // Round minute to nearest granularity
    minute = ((minute + 2.5) / 5) * 5;
    if (minute >= 60) {
        minute = 0;
        hour = (hour + 1) % 24;
    }
    
    // Calculate index into lookup table
    uint16_t index = (hour * 12) + (minute / 5);
    
    // Bounds check
    if (index >= LED_PATTERNS_COUNT) {
        return NULL;
    }
    
    return &led_patterns[index];
}

// Check if a specific LED should be on for the given pattern
static inline uint8_t is_led_on(const led_pattern_t* pattern, uint16_t led_index) {
    if (led_index >= LED_TOTAL_COUNT || pattern == NULL) {
        return 0;
    }
    
    uint16_t word_index = led_index / 32;
    uint8_t bit_index = led_index % 32;
    
    return (pattern->led_mask[word_index] & (1U << bit_index)) ? 1 : 0;
}

